import java.nio.file.*;
import java.io.*;
import java.util.List;

public class NIOExample {
    public static void main(String[] args) {
        // 1. Creating Paths
        System.out.println("=== Creating Paths ===");
        Path path1 = Paths.get("file.txt");
        Path path2 = Paths.get("myfolder", "subfolder", "file.txt");
        Path path3 = Paths.get("/absolute/path/file.txt");

        System.out.println("Path1: " + path1);
        System.out.println("Path2: " + path2);
        System.out.println("Path3: " + path3);

        // 2. Path operations
        System.out.println("=== Path Operations ===");
        Path path = Paths.get("parent/child/file.txt");
        System.out.println("Path: " + path);
        System.out.println("File name: " + path.getFileName());
        System.out.println("Parent: " + path.getParent());
        System.out.println("Root: " + path.getRoot());
        System.out.println("Name count: " + path.getNameCount());
        System.out.println("Name at 0: " + path.getName(0));

        // 3. Files utility class
        System.out.println("=== Files Utility ===");
        Path testFile = Paths.get("nio_test.txt");

        try {
            // Write content
            Files.write(testFile, "Hello, NIO!\nThis is a test.".getBytes());
            System.out.println("File written!");

            // Check file properties
            System.out.println("Exists: " + Files.exists(testFile));
            System.out.println("Size: " + Files.size(testFile) + " bytes");
            System.out.println("Is directory: " + Files.isDirectory(testFile));
            System.out.println("Is regular file: " + Files.isRegularFile(testFile));
            System.out.println("Can read: " + Files.isReadable(testFile));
            System.out.println("Can write: " + Files.isWritable(testFile));

            // Read all lines
            System.out.println("=== Reading all lines ===");
            List<String> lines = Files.readAllLines(testFile);
            for (String line : lines) {
                System.out.println("Line: " + line);
            }

            // Read all bytes
            System.out.println("=== Reading bytes ===");
            byte[] bytes = Files.readAllBytes(testFile);
            System.out.println("Content: " + new String(bytes));

            // Copy file
            System.out.println("=== Copying file ===");
            Path copyPath = Paths.get("nio_copy.txt");
            Files.copy(testFile, copyPath, StandardCopyOption.REPLACE_EXISTING);
            System.out.println("File copied!");

            // Move file
            System.out.println("=== Moving file ===");
            Path movePath = Paths.get("nio_moved.txt");
            Files.move(copyPath, movePath, StandardCopyOption.REPLACE_EXISTING);
            System.out.println("File moved to: " + movePath);

            // Delete file
            System.out.println("=== Deleting file ===");
            Files.delete(testFile);
            System.out.println("Original file deleted");
            Files.delete(movePath);
            System.out.println("Moved file deleted");

        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
            e.printStackTrace();
        }

        // 4. Creating directories
        System.out.println("=== Directories ===");
        try {
            Path dir = Paths.get("data/nio/subdir");
            Files.createDirectories(dir);  // Creates all parent directories
            System.out.println("Directories created: " + dir);

            Files.deleteIfExists(Paths.get("data/nio/subdir"));
            Files.deleteIfExists(Paths.get("data/nio"));
            Files.deleteIfExists(Paths.get("data"));
            System.out.println("Directories cleaned up");

        } catch (IOException e) {
            System.out.println("Directory error: " + e.getMessage());
        }

        // 5. File attributes
        System.out.println("=== Attributes ===");
        try {
            Path file = Paths.get("nio_test.txt");
            Files.write(file, "Test".getBytes());

            System.out.println("Last modified: " + Files.getLastModifiedTime(file));
            System.out.println("Owner: " + Files.getOwner(file));
            System.out.println("Is symbolic link: " + Files.isSymbolicLink(file));

            Files.delete(file);
        } catch (IOException e) {
            System.out.println("Attribute error: " + e.getMessage());
        }
    }
}

